var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"정말이야? 장교님이 우리랑 같은 식당을 쓰신다고?","JPN":"本当なのか？　将校が俺たちと同じ食堂で食べるってのは？","ENG":"Really? Officer Rashford eating together with us in the same cafeteria?","TWN":"真的嗎？軍官和我們在同一個地方用餐？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"이런 건 생전 먹어 볼 일이 없을 텐데, 입맛에 맞으려나?","JPN":"こんなもん、これまで食べたことないだろうに、口に合うのかな？","ENG":"But will the food be to her liking? I'm sure she's never had food like this before...","TWN":"她沒吃過這種東西吧？不知道合不合她的胃口？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_BORDER_NULL_C","text":{"KOREA":"맞을 리 있겠어? 수도에선 매일 고기요리를 먹을 텐데.","JPN":"合うわけないだろ？　首都では毎日肉料理食べてるはずだぜ。","ENG":"What do you think? I bet she used to eat meats like beef and pork every day back at the capital.","TWN":"怎麼可能會合她的胃口？她在首都每天都吃肉吧？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"…시선이 엄청나게 느껴지네요.","JPN":"……ものすごく視線を感じますね。","ENG":"I feel like everyone's staring at us...","TWN":"…感覺大家都在看我。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"신경 쓸 필요 없습니다. 식사를 마치는 대로 자릴 뜰 테니까요.","JPN":"気にする必要はありません。食事が終わり次第、出ますから。","ENG":"Don't mind them. We'll be leaving as soon as we're done eating.","TWN":"別在意，我們吃完飯就離開。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저희 수비대의 주식, 감자 스튜입니다. 조촐하지만 부디 맛있게 드시길.","JPN":"我々守備隊の主食であるジャガイモのシチューです。地味ですがどうぞ召し上がってください。","ENG":"This is our staple, potato stew. It's not much, but please enjoy.","TWN":"這是護衛隊的主食 馬鈴薯濃湯，粗茶淡飯，希望合你胃口。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래, 고맙군.","JPN":"ああ、感謝する。","ENG":"Very well. Thank you.","TWN":"好，謝謝。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"감자는 저희가 열심히 깎았습니다, 장교님!","JPN":"ジャガイモは僕たちが一生懸命剥きました！　将校！","ENG":"We peeled those potatoes just for you, Officer!","TWN":"軍官，馬鈴薯是我們努力削的！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"피터, 얼씬거리지 말고 빠져 있어라.","JPN":"ピーター、うろちょろしないで引っ込んでろ。","ENG":"Peter, stop bothering them with your tomfoolery.","TWN":"彼得，少在這礙眼，走開。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이것들아. 빠져 있으라고.","JPN":"おい。引っ込んでろって言ってるだろ。","ENG":"Didn't you all hear me?","TWN":"你們這些傢伙，全都走開。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"먼저 일어나 보겠습니다, 한나 씨.","JPN":"お先に失礼します、ハンナさん。","ENG":"Excuse me, I'll be going back to my room, Miss Anderson.","TWN":"我先走了，漢娜。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"앗… 벌써요?","JPN":"あっ……もうですか？","ENG":"Huh? Already?","TWN":"蛤… 這麼快喔？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그리고 수비대장은 잠깐 날 보도록 하지.","JPN":"あと、守備隊長は少し話がある。","ENG":"And I wish to see the Guard Captain, if you will.","TWN":"還有，護衛隊長來找我一下。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Understood.","TWN":"好的。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"뭐야? 반응이 왜 저래? 맛이 마음에 안 들었나?","JPN":"何だろう？　あの反応は。味が気に入らなかったのかな？","ENG":"Huh? What was that about? Did she not like the stew?","TWN":"什麼嘛？反應怎麼這樣？不喜歡吃喔？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}}]`);export{e as default};